mapper.select:
${pagingTop} SELECT site_id, add_id, os, browser, ip, add_dttm, member_group_name, menu_name, auth_code_id, change_type, module_type, homepage_name FROM ((SELECT a.site_id, a.add_id, a.os, a.browser, a.ip, to_char(a.add_dttm,'yyyy-mm-dd HH24:mi:ss') as add_dttm, c.member_group_name, menu_name, a.auth_code_id, a.change_type, a.module_type, d.homepage_name FROM admin_auth_log a, cms_menu b, wb_member_group c, cms_homepage d WHERE a.site_id = b.homepage_id AND a.site_id = d.homepage_id AND a.menu_idx = b.menu_idx AND a.module_type = 'SITE' AND a.member_group_idx = c.member_group_idx) UNION ALL (SELECT a.site_id,a.add_id, a.os, a.browser, a.ip, to_char(a.add_dttm,'yyyy-mm-dd HH24:mi:ss') as add_dttm, c.member_group_name, menu_name, a.auth_code_id, a.change_type, a.module_type, d.homepage_name FROM admin_auth_log a, cms_admin_menu b, wb_member_group c, cms_homepage d WHERE a.menu_idx = b.menu_idx AND a.site_id = d.homepage_id AND a.module_type = 'CMS' AND a.member_group_idx = c.member_group_idx)) WHERE 1=1
AND module_type = #{module_type}
AND to_date(add_dttm,'yyyy-mm-dd HH24:mi:ss') >= to_date(#{start_date},'yyyy-mm-dd HH24:mi:ss')
AND to_date(add_dttm,'yyyy-mm-dd HH24:mi:ss') <= to_date(#{end_date},'yyyy-mm-dd HH24:mi:ss')+1
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND change_type = #{search_type_1}
AND site_id = #{site_id}
ORDER BY add_dttm DESC ${pagingBottom}

SELECT COUNT(*) FROM( SELECT site_id, add_id, os, browser, ip, add_dttm, member_group_name, menu_name, auth_code_id, change_type, module_type FROM ((SELECT a.site_id, a.add_id, a.os, a.browser, a.ip, to_char(a.add_dttm,'yyyy-mm-dd HH24:mi:ss') as add_dttm, c.member_group_name, menu_name, a.auth_code_id, a.change_type, a.module_type FROM admin_auth_log a, cms_menu b, wb_member_group c WHERE a.site_id = b.homepage_id AND a.menu_idx = b.menu_idx AND a.module_type = 'SITE' AND a.member_group_idx = c.member_group_idx) UNION ALL (SELECT a.site_id,a.add_id, a.os, a.browser, a.ip, to_char(a.add_dttm,'yyyy-mm-dd HH24:mi:ss') as add_dttm, c.member_group_name, menu_name, a.auth_code_id, a.change_type, a.module_type FROM admin_auth_log a, cms_admin_menu b, wb_member_group c WHERE a.menu_idx = b.menu_idx AND a.module_type = 'CMS' AND a.member_group_idx = c.member_group_idx))) WHERE 1=1
AND module_type = #{module_type}
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND change_type = #{search_type_1}
AND to_date(add_dttm,'yyyy-mm-dd HH24:mi:ss') >= to_date(#{start_date},'yyyy-mm-dd HH24:mi:ss')
AND to_date(add_dttm,'yyyy-mm-dd HH24:mi:ss') <= to_date(#{end_date},'yyyy-mm-dd HH24:mi:ss')+1
AND site_id = #{site_id}

SELECT site_id,add_id, os, browser, ip, add_dttm, member_group_name, menu_name, auth_code_id, change_type, module_type FROM ((SELECT a.site_id,a.add_id, a.os, a.browser, a.ip, to_char(a.add_dttm,'yyyy-mm-dd HH24:mi:ss') as add_dttm, c.member_group_name, menu_name, a.auth_code_id, a.change_type, a.module_type FROM admin_auth_log a, cms_menu b, wb_member_group c WHERE a.site_id = b.homepage_id AND a.menu_idx = b.menu_idx AND a.module_type = 'SITE' AND a.member_group_idx = c.member_group_idx) UNION ALL (SELECT a.site_id,a.add_id, a.os, a.browser, a.ip, to_char(a.add_dttm,'yyyy-mm-dd HH24:mi:ss') as add_dttm, c.member_group_name, menu_name, a.auth_code_id, a.change_type, a.module_type FROM admin_auth_log a, cms_admin_menu b, wb_member_group c WHERE a.menu_idx = b.menu_idx AND a.module_type = 'CMS' AND a.member_group_idx = c.member_group_idx)) WHERE 1=1
AND module_type = #{module_type}
AND to_date(add_dttm,'yyyy-mm-dd HH24:mi:ss') >= to_date(#{start_date},'yyyy-mm-dd HH24:mi:ss')
AND to_date(add_dttm,'yyyy-mm-dd HH24:mi:ss') <= to_date(#{end_date},'yyyy-mm-dd HH24:mi:ss')+1
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND change_type = #{search_type_1}
AND site_id = #{site_id}
ORDER BY add_dttm DESC
